import data from './data';


type DataCallback = (err?, data?)=>void;

interface Params {
    ids?: string[];
    [x: string]: any;
}

function callAsync(callback:Function, ...args:any[]) {
    process.nextTick( () => {
        callback(...args);
    });
}


// example calls to emulate:
// JSC.config.update(credentials);
