import path = require('path');
import findRoot = require('find-root');
import {EventEmitter} from 'events';
import {instantiateService} from '../../SSMService';
// import {RegistryClient} from 'jibo-service-framework';
// import {SystemManagerClient} from 'jibo-client-framework';
import MediaManagerService from '../../services/media-manager/MediaManagerService';

import parentLog from '../../services/log';
const log = parentLog.createChild('MMS');


class MMSProcess extends EventEmitter {

    constructor() {
        super();

        // process.on('SIGINT', function(event) {
        //     log.debug("Caught interrupt signal");
        //     setTimeout(() => {
        //         log.debug('REALLY EXIT');
        //         process.exit();
        //     }, 5000);
        // });

        let httpRoot:string = path.join(findRoot(__dirname), 'static/media-manager-service');

        instantiateService(MediaManagerService, {port: 8488}, httpRoot);
        MediaManagerService.instance.init( (err) => {
            log.iferr(err, 'error initing MediaManagerService');

            let sem = require('node-semaphore');
            log.debug('SEMAPHORE', 'pid', process.pid);
            let s = sem.Semaphore('/jibo-startup-' + process.pid + '.event');
            s.post();

            log.info('MMS Started');
        });
    }
}

export default function() {
    return new MMSProcess();
}
